// Use "take" to view a sample number of records in the table and check the data.
YOUR_TABLE_HERE
| take 100

// See how many records are in the table.
YOUR_TABLE_HERE
| count

// This query returns the number of ingestions per hour in the given table.
YOUR_TABLE_HERE
| summarize IngestionCount = count() by bin(ingestion_time(), 1h)

.create-or-alter function with (
    view = true,
    docstring = 'Unified monitoring semantic model logs from all workspace monitoring databases',
    folder = 'VirtualTables'
)
AllSemanticModelLogs() {
    union isfuzzy=true withsource=SourceWorkspace
        (
            cluster('https://trd-e1bkwnx6evnruyg5jn.z6.kusto.fabric.microsoft.com').database('Monitoring Eventhouse').SemanticModelLogs
            | where Timestamp > ago(30d)
            | extend Workspace = "Alpha"
        ),
        (
            cluster('https://trd-822mxvyzxqs4eq1wjd.z3.kusto.fabric.microsoft.com').database('Monitoring Eventhouse').SemanticModelLogs
            | where Timestamp > ago(30d)
            | extend Workspace = "Pv2"
        ),
        (
            cluster('https://trd-3eafpxpagejm0nuw4z.z0.kusto.fabric.microsoft.com').database('Monitoring Eventhouse').SemanticModelLogs
            | where Timestamp > ago(30d)
            | extend Workspace = "Dev"
        )
}

